(120, 'ASHOK BALAJI R', 'ashokbala98765@gmail.com', 'RHIN0000111', '[\"Dr. Anoop Raj Award - Poster Session\"]', NULL, '', NULL, NULL, '', NULL, NULL, '', NULL, NULL, '', NULL, 'Background:\r\nRhinosporidiosis is a chronic granulomatous disease caused by Rhinosporidium seeberi, primarily affecting the nasal mucosa and nasopharynx. Involvement of the Eustachian tubes is extremely rare and poses significant diagnostic and therapeutic challenges, especially in recurrent cases.\r\n\r\nCase Presentation:\r\nA 47-year-old male with a history of recurrent rhinosporidiosis presented with epistaxis. Anterior rhinoscopy revealed a pinkish, proliferative mass with visible spores involving both nasal cavities, inferior and middle turbinates. The nasal septum was obscured. Surgical excision under general anesthesia revealed unexpected extension of the mass into both Eustachian tube openings. Complete excision was performed, followed by cauterization to reduce recurrence risk.\r\n\r\nPostoperative Course:\r\nAt one-week follow-up, the patient reported aural fullness. Impedance audiometry showed a Type C tympanogram, suggesting Eustachian tube dysfunction likely due to postoperative inflammation or fibrosis. At two months, he continued to report aural symptoms. Audiometry revealed a right Type A curve and left Type B curve, indicating persistent dysfunction on the left side.\r\n\r\nConclusion:\r\nThis case highlights an unusual and rare involvement of bilateral Eustachian tubes in rhinosporidiosis, emphasizing the importance of careful intraoperative evaluation in recurrent cases. Postoperative Eustachian tube dysfunction is a potential complication that requires monitoring and management. Long-term follow-up is crucial due to the high recurrence rate of this condition.', '', 'Unmasking the Unusual: Bilateral Eustachian Tube Involvement in Recurrent Rhinosporidiosis', 2, 1, '2025-09-30 14:46:37', '2025-09-30 14:46:41'),
(121, 'ASHOK BALAJI R', 'ashokbala98765@gmail.com', 'RHIN0000111', '[\"Dr. Anoop Raj Award - Poster Session\"]', NULL, '', NULL, NULL, '', NULL, NULL, '', NULL, NULL, '', NULL, 'Background:\r\nRhinosporidiosis is a chronic granulomatous disease caused by Rhinosporidium seeberi, primarily affecting the nasal mucosa and nasopharynx. Involvement of the Eustachian tubes is extremely rare and poses significant diagnostic and therapeutic challenges, especially in recurrent cases.\r\n\r\nCase Presentation:\r\nA 47-year-old male with a history of recurrent rhinosporidiosis presented with epistaxis. Anterior rhinoscopy revealed a pinkish, proliferative mass with visible spores involving both nasal cavities, inferior and middle turbinates. The nasal septum was obscured. Surgical excision under general anesthesia revealed unexpected extension of the mass into both Eustachian tube openings. Complete excision was performed, followed by cauterization to reduce recurrence risk.\r\n\r\nPostoperative Course:\r\nAt one-week follow-up, the patient reported aural fullness. Impedance audiometry showed a Type C tympanogram, suggesting Eustachian tube dysfunction likely due to postoperative inflammation or fibrosis. At two months, he continued to report aural symptoms. Audiometry revealed a right Type A curve and left Type B curve, indicating persistent dysfunction on the left side.\r\n\r\nConclusion:\r\nThis case highlights an unusual and rare involvement of bilateral Eustachian tubes in rhinosporidiosis, emphasizing the importance of careful intraoperative evaluation in recurrent cases. Postoperative Eustachian tube dysfunction is a potential complication that requires monitoring and management. Long-term follow-up is crucial due to the high recurrence rate of this condition.', '', 'Unmasking the Unusual: Bilateral Eustachian Tube Involvement in Recurrent Rhinosporidiosis', 2, 1, '2025-09-30 14:46:40', '2025-09-30 14:46:43'),
(122, 'Devanand K', 'devanand.kannabiran92@gmail.com', 'RHIN0000334', '[\"Dr. Arvind Soni Award - Video Session\"]', NULL, '', NULL, NULL, '', NULL, NULL, '', NULL, 'Introduction: Surgical management of brainstem cavernous malformations is challenging due to their delicate location and complex accessibility. To date, advances in endoscopic techniques have enabled the reporting of ten cases of endoscopic transnasal resection of cavernous malformations in the literature. We introduce a groundbreaking technique for resecting these lesions. \r\nCase Summary: A one-year-nine-month-old infant presented with a 3-day history of difficulty walking, difficulty swallowing, and difficulty holding objects with her right hand. She was diagnosed with acute onset right hemiparesis with involvement of cranial nerves 6, 7, 9, and 10. Three months later, she returned to the emergency room with Cheyne-stokes breathing, drowsiness and was intubated. She underwent extended endoscopic transnasal transclival excision of the pontine cavernoma. Postoperative evaluation revealed significant neurological improvement with minimal morbidity.\r\nConclusion: We selected an anteromedial endoscopic endonasal approach because the lesion had displaced white matter tracts laterally rendering an anteromedial corridor the least traumatic pathway.', '', 'PEDIATRIC PONS, TARGETED PATHWAY: ENDOSCOPIC APPROACH FOR INFANTILE PONTINE CAVERNOMA', NULL, '', NULL, 2, 1, '2025-09-30 21:27:56', '2025-09-30 21:27:59'),
